from prometheus_client import Collector, GaugeMetricFamily, start_http_server
import sqlite3

# Define Prometheus metrics
db_connection_gauge = GaugeMetricFamily('db_connection', 'Database connection status.', labels=['username', 'password', 'host'])

def check_db_connection(username, password, host):
    try:
        conn = sqlite3.connect(f'sqlite:///{host}')
        conn.close()
        return True
    except Exception as e:
        print(f"Error checking database connection: {e}")
        return False

